parameters.jsCode:
const output = [];
const notifiedManagers = new Set();

for (const item of $input.all()) {
  const {
    project_id,
    project_title,
    new_project_status,     // ✅ NEW FIELD
    status_changed_at,      // optional but useful
    project_manager_email,
    team_user_email
  } = item.json;

  // Team member → every row
  if (team_user_email) {
    output.push({
      json: {
        email: team_user_email,
        role: 'team',
        project_title,
        project_status: new_project_status,   // ✅ latest status
        status_changed_at
      }
    });
  }

  // Project manager → only once per project
  if (
    project_manager_email &&
    !notifiedManagers.has(project_id)
  ) {
    notifiedManagers.add(project_id);
    output.push({
      json: {
        email: project_manager_email,
        role: 'manager',
        project_title,
        project_status: new_project_status,   // ✅ latest status
        status_changed_at
      }
    });
  }
}

return output;
